insert into public.itinera_sources(id,title,url,category,usefulness,official,jurisdiction)
values
('itinerarios-modulares-adultos-galicia-2026','Xunta FP · itinerarios modulares para réxime de persoas adultas','https://www.edu.xunta.gal/fp/oferta-fp','fp_modular','Documentación achegada con recomendacións de módulos e itinerarios para cursar ciclos polo réxime de persoas adultas.',true,'Galicia'),
('uvigo-estudos-grao','Universidade de Vigo · estudos de grao','https://www.uvigo.gal/estudar/que-estudar/estudos-grao','universidade','Relación de estudos de grao da Universidade de Vigo segundo documentación achegada.',true,'Galicia'),
('mefp-becas-xerais','Ministerio de Educación · becas xerais','https://www.becaseducacion.gob.es/','becas','Información sobre becas xerais para estudos postobrigatorios.',true,'España'),
('mefp-becas-neae','Ministerio de Educación · axudas NEAE','https://www.becaseducacion.gob.es/','becas_neae','Información sobre axudas para alumnado con necesidade específica de apoio educativo.',true,'España')
insert into public.itinera_academic_guide(id,title,category,body,raw) values
('bacharelato','Bacharelato','orientacion','Etapa postobrigatoria de dous cursos que prepara para universidade, FP superior e outras vías. A modalidade debe escollerse segundo meta posterior, ponderacións e rendemento realista.',jsonb_build_object('source_upload','2 base datos itinera.zip','version','0.35')),
('fp','Formación Profesional','orientacion','Ensino organizado en módulos profesionais. Inclúe FP básica, grao medio, grao superior e cursos de especialización. Permite emprego e continuidade académica.',jsonb_build_object('source_upload','2 base datos itinera.zip','version','0.35')),
('modular','Réxime modular de persoas adultas','orientacion','Permite matrícula por módulos profesionais, con itinerarios flexibles para persoas adultas. Debe comprobarse oferta anual, centro, modalidade e prazas.',jsonb_build_object('source_upload','2 base datos itinera.zip','version','0.35')),
('universidade','Universidade: graos, másteres e doutoramentos','orientacion','O grao é o primeiro nivel universitario oficial; o máster especializa ou habilita; o doutoramento é a etapa investigadora que culmina coa tese.',jsonb_build_object('source_upload','2 base datos itinera.zip','version','0.35')),
('becas','Becas xerais e NEAE','orientacion','As becas xerais dependen de requisitos económicos e académicos. As NEAE requiren cumprir supostos e documentación da convocatoria.',jsonb_build_object('source_upload','2 base datos itinera.zip','version','0.35')),
('glosario','Glosario académico','orientacion','ABAU, RUCT, QEDU, ECTS, nota de corte, ponderación, FCT, módulo, título oficial, prazas, modalidade, campus e demais termos clave.',jsonb_build_object('source_upload','2 base datos itinera.zip','version','0.35'))
