-- ITINERA v0.35 · documentación académica ampliada, UVigo e itinerarios modulares
-- Ejecutar en Supabase SQL Editor después de v0.34.1.
begin;

-- Fuentes documentales aportadas en "2 base datos itinera.zip".
on conflict (id) do update
set title=excluded.title,
    url=excluded.url,
    category=excluded.category,
    usefulness=excluded.usefulness,
    official=excluded.official,
    jurisdiction=excluded.jurisdiction,
    updated_at=now();

create table if not exists public.itinera_adult_modular_itineraries (
  id text primary key,
  code text,
  title text not null,
  source_file text,
  modules jsonb not null default '[]'::jsonb,
  raw jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.itinera_academic_guide (
  id text primary key,
  title text not null,
  category text not null default 'orientacion',
  body text not null,
  raw jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

on conflict (id) do update set title=excluded.title,category=excluded.category,body=excluded.body,raw=excluded.raw,updated_at=now();

on conflict (id) do update set code=excluded.code,title=excluded.title,source_file=excluded.source_file,modules=excluded.modules,raw=excluded.raw,updated_at=now();

on conflict (id) do update set name=excluded.name,level=excluded.level,family=excluded.family,route=excluded.route,subjects=excluded.subjects,ponderation_subjects=excluded.ponderation_subjects,availability_by_province=excluded.availability_by_province,sources=excluded.sources,source_url=excluded.source_url,source_id=excluded.source_id,raw=excluded.raw,data_quality=excluded.data_quality,verified_at=excluded.verified_at,last_seen_at=excluded.last_seen_at,updated_at=now();

commit;
